const payload = $('Webhook').first()?.json?.body?.payload;

const text =
  typeof payload === "string"
    ? payload
    : payload == null
      ? ""
      : JSON.stringify(payload);

const prefix = "https://us.1prompt.com/conversations-assets/location/";
const escapedPrefix = prefix.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

const re = new RegExp(
  String.raw`Attachment:\s*(${escapedPrefix}[^\s"'<>]+)`,
  "gi"
);

const urls = [];
const seen = new Set();
let match;

while ((match = re.exec(text)) !== null) {
  const url = match[1].trim().replace(/[)\],.]+$/g, "");
  if (!seen.has(url)) {
    seen.add(url);
    urls.push(url);
  }
}

const hasAttachments = urls.length > 0 ? "Yes" : "No";

return [
  {
    json: {
      hasAttachments,
      attachmentUrls: urls,
      attachmentUrl: urls[0] || "",
      count: urls.length,
    },
  },
];

