const webhookData = $('Webhook').first().json;

// Try all possible locations for Setter_Number
const rawSetterNumber =
  webhookData.body?.Setter_Number ??
  webhookData.query?.Setter_Number ??
  webhookData.Setter_Number;

const setterNumber = parseInt(rawSetterNumber, 10);

if (!setterNumber || isNaN(setterNumber)) {
  throw new Error(
    `Invalid Setter_Number. body=${JSON.stringify(webhookData.body?.Setter_Number)} query=${JSON.stringify(webhookData.query?.Setter_Number)}`
  );
}

// Handle different shapes from Aggregate node
let rawInput = $input.first().json;
let data = rawInput.data;

if (Array.isArray(data) && data.length === 1 && Array.isArray(data[0])) {
  data = data[0];
}
if (!Array.isArray(data) && data?.data) {
  data = data.data;
}

if (!Array.isArray(data)) {
  throw new Error(
    `Expected array of setter rows, got: ${typeof data}. Raw input keys: ${Object.keys(rawInput).join(', ')}`
  );
}

const targetCardName = `Setter-${setterNumber}`;
const setter = data.find(row => row && row.card_name === targetCardName);

if (!setter) {
  const availableCards = data.map(r => r?.card_name ?? 'null').join(', ');
  throw new Error(
    `${targetCardName} not found. Rows received: ${data.length}. Available card_names: [${availableCards}]`
  );
}

return [{
  json: {
    Setter_Number: setterNumber,
    Card_Name: setter.card_name,
    System_Prompt: setter.system_prompt || "",
    Booking_Prompt: setter.booking_prompt || "",
    LLM_Model: setter.model || "",
    Response_Delay: setter.response_delay_seconds,
    FollowUp_Delay: setter.followup_delay_seconds,
    File_Processing_Enabled: setter.file_processing_enabled,
    Human_Transfer_Enabled: setter.human_transfer_enabled,
    Booking_Function_Enabled: setter.booking_function_enabled,
    Prompt_Configuration: setter.prompt_configurations || {}
  }
}];

const messages = $input.first().json?.messages?.messages || [];

if (messages.length === 0) {
  return [{ json: { messageId: null, noMessages: true } }];
}

return messages.map(msg => ({
  json: {
    messageId: msg.id,
    direction: msg.direction,
    message: msg.body,
    messageType: msg.messageType,
    dateAdded: msg.dateAdded || msg.createdAt || ''
  }
}));

const rawMessages = $('getGHL_Messages').first().json;

// If there's an error or no messages, skip entirely
if (rawMessages.error || !rawMessages.messages) {
  return [{ json: { human_agent_messages: [], human_agent_context: '', count: 0 } }];
}

const allMessages = rawMessages.messages.messages || [];

const supabaseHistory = $('Get Chat History1').item.json.messages || [];

const supabaseContents = new Set(
  supabaseHistory.flatMap(m => [
    (m.ai || '').trim().toLowerCase(),
    (m.human || '').trim().toLowerCase()
  ]).filter(s => s.length > 0)
);

const processedMessages = allMessages
  .map(item => {
    const msg = item.message || item;
    const body = msg.body || msg.text || msg.content || msg.message || '';
    const direction = msg.direction || item.direction || '';
    const dateAdded = msg.dateAdded || msg.createdAt || item.dateAdded || '';
    return { body, direction, dateAdded };
  })
  .filter(msg => {
    const content = msg.body.trim();
    return content.length > 0 && !supabaseContents.has(content.toLowerCase());
  });

const missedMessages = processedMessages.map(msg => ({
  role: msg.direction === 'outbound' ? 'Human Agent' : 'Contact',
  content: msg.body.trim(),
  timestamp: msg.dateAdded
}));

missedMessages.sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

const human_agent_context = missedMessages.length > 0
  ? missedMessages.map(m => `[${m.timestamp}] ${m.role}: ${m.content}`).join('\n')
  : '';

return [{ json: { human_agent_messages: missedMessages, human_agent_context, count: missedMessages.length } }];

